import {
  CardDef,
  Component,
  field,
  contains,
} from 'https://cardstack.com/base/card-api';
import StringField from 'https://cardstack.com/base/string';

import UserIcon from '@cardstack/boxel-icons/user';
import Avatar from '../fields/avatar';
import AvatarCreatorComponent from './components/avatar-creator';
import { AvataaarsModel } from '../utils/external/avataar';
import { restartableTask } from 'ember-concurrency';
import { CreateRealImage } from '../commands/create-real-image';

class IsolatedTemplate extends Component<typeof AvatarCreator> {
  // Convert avatar field to the format expected by the component
  get avatarModel() {
    return {
      topType: this.args.model.avatar?.topType,
      accessoriesType: this.args.model.avatar?.accessoriesType,
      hairColor: this.args.model.avatar?.hairColor,
      facialHairType: this.args.model.avatar?.facialHairType,
      clotheType: this.args.model.avatar?.clotheType,
      eyeType: this.args.model.avatar?.eyeType,
      eyebrowType: this.args.model.avatar?.eyebrowType,
      mouthType: this.args.model.avatar?.mouthType,
      skinColor: this.args.model.avatar?.skinColor,
    };
  }

  updateAvatar = (model: AvataaarsModel) => {
    this.args.model.avatar = new Avatar(model);
  };

  _createRealImageTask = () => {
    this.createRealImageTask.perform();
  };

  private createRealImageTask = restartableTask(async () => {
    let commandContext = this.args.context?.commandContext;
    if (!commandContext) {
      throw new Error('No command context found');
    }

    const createRealImageCommand = new CreateRealImage(commandContext);

    await createRealImageCommand.execute({
      avatar: this.args.model.avatar, // Pass the Avatar field (not the plain model)
      avatarUrl: this.args.model?.cardThumbnailURL, // The thumbnailURL field is used in prompts as a reference image
      notes: this.args.model.cardInfo?.notes, // The cardInfo notes field is used in prompts as context
    });

    return createRealImageCommand.result;
  });

  get isImageGenerating() {
    return this.createRealImageTask.isRunning;
  }

  get generatedImage() {
    const result = this.createRealImageTask.lastSuccessful?.value;
    return result?.success && result?.imageUrl ? result.imageUrl : '';
  }

  get errorImageGenerating() {
    const result = this.createRealImageTask.last?.value;
    return result?.success ? '' : result?.error || '';
  }

  <template>
    <AvatarCreatorComponent
      @model={{this.avatarModel}}
      @context={{@context}}
      @onUpdate={{this.updateAvatar}}
      @isImageGenerating={{this.isImageGenerating}}
      @generatedImage={{this.generatedImage}}
      @errorImageGenerating={{this.errorImageGenerating}}
      @onCreateRealImage={{this._createRealImageTask}}
    />
  </template>
}

export class AvatarCreator extends CardDef {
  static displayName = 'Avatar Creator';
  static icon = UserIcon;
  static prefersWideFormat = true;

  @field avatar = contains(Avatar, {
    description: 'Avatar appearance configuration',
  });

  @field cardTitle = contains(StringField, {
    computeVia: function (this: AvatarCreator) {
      return 'Avatar';
    },
  });

  @field cardThumbnailURL = contains(StringField, {
    computeVia: function (this: AvatarCreator) {
      return this.avatar?.cardThumbnailURL || '';
    },
  });

  static isolated = IsolatedTemplate;
}

import {
  FieldDef,
  field,
  contains,
  Component,
} from 'https://cardstack.com/base/card-api';
import StringField from 'https://cardstack.com/base/string';
import UserIcon from '@cardstack/boxel-icons/user';
import { getAvataarsUrl, AvataaarsModel } from '../utils/external/avataar';
import AvatarComponent from './components/avatar';

class EditTemplate extends Component<typeof Avatar> {
  // Convert avatar field to the format expected by the component
  get avatarModel() {
    return {
      topType: this.args.model.topType,
      accessoriesType: this.args.model.accessoriesType,
      hairColor: this.args.model.hairColor,
      facialHairType: this.args.model.facialHairType,
      clotheType: this.args.model.clotheType,
      eyeType: this.args.model.eyeType,
      eyebrowType: this.args.model.eyebrowType,
      mouthType: this.args.model.mouthType,
      skinColor: this.args.model.skinColor,
    };
  }

  updateAvatar = (model: AvataaarsModel) => {
    this.args.model.topType = model.topType;
    this.args.model.accessoriesType = model.accessoriesType;
    this.args.model.hairColor = model.hairColor;
    this.args.model.facialHairType = model.facialHairType;
    this.args.model.clotheType = model.clotheType;
    this.args.model.eyeType = model.eyeType;
    this.args.model.eyebrowType = model.eyebrowType;
    this.args.model.mouthType = model.mouthType;
    this.args.model.skinColor = model.skinColor;
  };

  <template>
    <AvatarComponent
      @model={{this.avatarModel}}
      @context={{@context}}
      @onUpdate={{this.updateAvatar}}
    />
  </template>
}

export default class Avatar extends FieldDef {
  static displayName = 'Avatar';
  static icon = UserIcon;

  @field topType = contains(StringField, {
    description: 'Selected hair/top style',
  });

  @field accessoriesType = contains(StringField, {
    description: 'Selected accessories type',
  });

  @field hairColor = contains(StringField, {
    description: 'Selected hair color',
  });

  @field facialHairType = contains(StringField, {
    description: 'Selected facial hair type',
  });

  @field clotheType = contains(StringField, {
    description: 'Selected clothing type',
  });

  @field eyeType = contains(StringField, {
    description: 'Selected eye type',
  });

  @field eyebrowType = contains(StringField, {
    description: 'Selected eyebrow type',
  });

  @field mouthType = contains(StringField, {
    description: 'Selected mouth type',
  });

  @field skinColor = contains(StringField, {
    description: 'Selected skin color',
  });

  @field cardThumbnailURL = contains(StringField, {
    computeVia: function (this: Avatar) {
      return getAvataarsUrl({
        topType: this.topType,
        accessoriesType: this.accessoriesType,
        hairColor: this.hairColor,
        facialHairType: this.facialHairType,
        clotheType: this.clotheType,
        eyeType: this.eyeType,
        eyebrowType: this.eyebrowType,
        mouthType: this.mouthType,
        skinColor: this.skinColor,
      });
    },
  });

  static embedded = EditTemplate;
  static edit = EditTemplate;
}

export interface AvataaarsModel {
  topType?: string;
  accessoriesType?: string;
  hairColor?: string;
  facialHairType?: string;
  clotheType?: string;
  eyeType?: string;
  eyebrowType?: string;
  mouthType?: string;
  skinColor?: string;
}

export interface AvataaarsOption {
  value: string;
