          </div>
        </div>
      </div>
    </main>

    <style scoped>
      .avatar-creator-container {
        container-type: inline-size;
      }
      .avatar-creator {
        display: grid;
        grid-template-columns: 420px 1fr;
        gap: var(--boxel-sp-xl);
